     1→"use client";
     2→
     3→import * as React from "react";
     4→import { Button } from "@/components/ui/button";
     5→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
     6→import { getSocket } from "@/lib/socketClient";
     7→import { triggerBoatAnimation } from "@/components/boat-animation";
     8→import { playAdminAlert, playCustomerNotification } from "@/lib/queueSounds";
     9→import type { QueueResponseAdminDTO, QueueResponseCustomerDTO } from "@/lib/apiTypes";
    10→
    11→type QueueType = "LAUNCH" | "RETRIEVAL";
    12→
    13→export function CombinedQueueClient({ isAdmin }: { isAdmin: boolean }) {
    14→  type QueueData = QueueResponseAdminDTO | QueueResponseCustomerDTO;
    15→  const [launchData, setLaunchData] = React.useState<QueueData | null>(null);
    16→  const [retrievalData, setRetrievalData] = React.useState<QueueData | null>(null);
    17→  const [loading, setLoading] = React.useState(true);
    18→  const [error, setError] = React.useState<string | null>(null);
    19→  const [actionPendingId, setActionPendingId] = React.useState<string | null>(null);
    20→
    21→  const load = React.useCallback(async () => {
    22→    setError(null);
    23→    setLoading(true);
    24→    try {
    25→      const [launchRes, retrievalRes] = await Promise.all([
    26→        fetch(`/api/queues/LAUNCH`, { cache: "no-store" }),
    27→        fetch(`/api/queues/RETRIEVAL`, { cache: "no-store" }),
    28→      ]);
    29→
    30→      if (!launchRes.ok || !retrievalRes.ok) {
    31→        setError("Failed to load queues");
    32→        setLoading(false);
    33→        return;
    34→      }
    35→
    36→      const [launch, retrieval] = await Promise.all([launchRes.json(), retrievalRes.json()]);
    37→      setLaunchData(launch);
    38→      setRetrievalData(retrieval);
    39→    } catch {
    40→      setError("Failed to load queues");
    41→    } finally {
    42→      setLoading(false);
    43→    }
    44→  }, []);
    45→
    46→  async function markCompleted(id: string, type: QueueType) {
    47→    if (!isAdmin) return;
    48→    setActionPendingId(id);
    49→    try {
    50→      await fetch(`/api/admin/bookings/${id}`, {
    51→        method: "PATCH",
    52→        headers: { "content-type": "application/json" },
    53→        body: JSON.stringify({ action: "MARK_COMPLETED" }),
    54→      });
    55→      triggerBoatAnimation(type === "LAUNCH" ? "launch" : "retrieval");
    56→      await load();
    57→    } finally {
    58→      setActionPendingId(null);
    59→    }
    60→  }
    61→
    62→  React.useEffect(() => {
    63→    load();
    64→    let active = true;
    65→    const refreshInterval = setInterval(() => { if (active) load(); }, 3 * 60 * 1000);
    66→    (async () => {
    67→      const socket = await getSocket();
    68→      if (!active) return;
    69→      socket.emit("queues:subscribe", {});
    70→      const onUpdated = () => {
    71→        load();
    72→        if (isAdmin) playAdminAlert();
    73→        else playCustomerNotification();
    74→      };
    75→      socket.on("queues:updated", onUpdated);
    76→      return () => {
    77→        socket.off("queues:updated", onUpdated);
    78→      };
    79→    })();
    80→    return () => {
    81→      active = false;
    82→      clearInterval(refreshInterval);
    83→    };
    84→  }, [load]);
    85→
    86→  const renderQueueSection = (type: QueueType, data: QueueData | null) => {
    87→    const pending = data?.pending ?? [];
    88→    const completed = data?.completed ?? [];
    89→    const title = type === "LAUNCH" ? "Launch Queue" : "Retrieval Queue";
    90→    const buttonLabel = type === "LAUNCH" ? "Launched" : "Retrieved";
    91→
    92→    return (
    93→      <div className="space-y-4">
    94→        <h2 className={`text-lg font-semibold ${type === "LAUNCH" ? "text-green-700" : "text-red-700"}`}>
    95→          {title} ({pending.length + completed.length})
    96→        </h2>
    97→
    98→        {error && type === "LAUNCH" ? (
    99→          <div className="rounded-xl bg-red-50 p-4 text-sm text-red-700">{error}</div>
   100→        ) : null}
   101→
   102→        <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
   103→          {/* Pending */}
   104→          <Card>
   105→            <CardHeader>
   106→              <CardTitle>
   107→                Pending ({pending.length})
   108→                {isAdmin ? <span className="ml-2 text-xs font-medium text-zinc-500">(staff view)</span> : null}
   109→              </CardTitle>
   110→            </CardHeader>
   111→            <CardContent>
   112→              {loading ? (
   113→                <div className="text-sm text-zinc-600">Loading…</div>
   114→              ) : pending.length === 0 ? (
   115→                <div className="text-sm text-zinc-600">No pending requests.</div>
   116→              ) : (
   117→                <div className="space-y-2">
   118→                  {pending.map((b, i) => {
   119→                    const adminB = isAdmin ? (b as QueueResponseAdminDTO["pending"][number]) : null;
   120→                    const custB = !isAdmin ? (b as QueueResponseCustomerDTO["pending"][number]) : null;
   121→                    return (
   122→                      <div
   123→                        key={b.id}
   124→                        className="flex items-start justify-between gap-2 rounded-lg border border-zinc-100 bg-zinc-50 p-3"
   125→                      >
   126→                        <div className="flex items-start gap-3 min-w-0">
   127→                          <span className={`mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full text-xs font-bold text-white ${type === "LAUNCH" ? "bg-green-700" : "bg-red-700"}`}>
   128→                            {i + 1}
   129→                          </span>
   130→                          <div className="min-w-0 space-y-0.5">
   131→                            <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
   132→                              <span className="font-semibold text-zinc-900 text-sm">
   133→                                {adminB ? adminB.vessel.boatName : custB?.vessel.boatName}
   134→                              </span>
   135→                              {b.vessel?.yardNumber ? (
   136→                                <span className="text-xs font-medium text-zinc-500">Yard #{b.vessel.yardNumber}</span>
   137→                              ) : null}
   138→                              {b.vessel?.owner?.username ? (
   139→                                <span className="rounded-full bg-sky-100 px-2 py-0.5 text-xs font-bold text-sky-700">@{b.vessel.owner.username}</span>
   140→                              ) : null}
   141→                            </div>
   142→                            <div className="flex flex-wrap items-center gap-x-3 gap-y-0.5 text-xs text-zinc-600">
   143→                              {adminB ? (
   144→                                <>
   145→                                  {adminB.vessel.boatType ? <span>{adminB.vessel.boatType}</span> : null}
   146→                                  {adminB.vessel.boatNumber ? <span>#{adminB.vessel.boatNumber}</span> : null}
   147→                                  <span className="font-medium text-zinc-700">{adminB.vessel.owner.name}</span>
   148→                                  {adminB.vessel.owner.phone ? (
   149→                                    <a href={`tel:${adminB.vessel.owner.phone}`} className="text-sky-600 hover:underline">
   150→                                      {adminB.vessel.owner.phone}
   151→                                    </a>
   152→                                  ) : null}
   153→                                </>
   154→                              ) : (
   155→                                <>
   156→                                  {custB?.vessel.boatType ? <span>{custB.vessel.boatType}</span> : null}
   157→                                  <span className="font-medium text-zinc-700">{custB?.vessel.owner.name}</span>
   158→                                </>
   159→                              )}
   160→                            </div>
   161→                            <div className="flex flex-wrap items-center gap-2 mt-1">
   162→                              {b.stayingOnMooring ? (
   163→                                <span className="inline-flex items-center rounded-full bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-700">
   164→                                  Staying on mooring
   165→                                </span>
   166→                              ) : null}
   167→                              <span className="text-xs text-zinc-400">
   168→                                {b.requestedAt ? new Date(b.requestedAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) : "—"}
   169→                              </span>
   170→                            </div>
   171→                          </div>
   172→                        </div>
   173→                        {isAdmin ? (
   174→                          <Button
   175→                            size="sm"
   176→                            variant="secondary"
   177→                            className="shrink-0 text-xs"
   178→                            disabled={actionPendingId === b.id}
   179→                            onClick={() => markCompleted(b.id, type)}
   180→                          >
   181→                            {actionPendingId === b.id ? "…" : buttonLabel}
   182→                          </Button>
   183→                        ) : null}
   184→                      </div>
   185→                    );
   186→                  })}
   187→                </div>
   188→              )}
   189→            </CardContent>
   190→          </Card>
   191→
   192→          {/* Completed */}
   193→          <Card>
   194→            <CardHeader>
   195→              <CardTitle>Completed ({completed.length})</CardTitle>
   196→            </CardHeader>
   197→            <CardContent>
   198→              {loading ? (
   199→                <div className="text-sm text-zinc-600">Loading…</div>
   200→              ) : completed.length === 0 ? (
   201→                <div className="text-sm text-zinc-600">None completed yet.</div>
   202→              ) : (
   203→                <div className="space-y-2">
   204→                  {completed.map((b) => {
   205→                    const adminB = isAdmin ? (b as QueueResponseAdminDTO["completed"][number]) : null;
   206→                    const custB = !isAdmin ? (b as QueueResponseCustomerDTO["completed"][number]) : null;
   207→                    return (
   208→                      <div
   209→                        key={b.id}
   210→                        className="flex items-start gap-3 rounded-lg border border-zinc-100 bg-zinc-50 p-3 opacity-70"
   211→                      >
   212→                        <span className="mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center rounded-full bg-zinc-400 text-xs text-white">✓</span>
   213→                        <div className="min-w-0 space-y-0.5">
   214→                          <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
   215→                            <span className="font-semibold text-zinc-900 text-sm">
   216→                              {adminB ? adminB.vessel.boatName : custB?.vessel.boatName}
   217→                            </span>
   218→                            {b.vessel?.yardNumber ? (
   219→                              <span className="text-xs font-medium text-zinc-500">Yard #{b.vessel.yardNumber}</span>
   220→                            ) : null}
   221→                            {b.vessel?.owner?.username ? (
   222→                              <span className="rounded-full bg-zinc-100 px-2 py-0.5 text-xs font-bold text-zinc-600">@{b.vessel.owner.username}</span>
   223→                            ) : null}
   224→                          </div>
   225→                          <div className="flex flex-wrap items-center gap-x-3 gap-y-0.5 text-xs text-zinc-500">
   226→                            {adminB ? (
   227→                              <>
   228→                                {adminB.vessel.boatNumber ? <span>#{adminB.vessel.boatNumber}</span> : null}
   229→                                <span>{adminB.vessel.owner.name}</span>
   230→                                {adminB.vessel.owner.phone ? (
   231→                                  <a href={`tel:${adminB.vessel.owner.phone}`} className="text-sky-600 hover:underline">{adminB.vessel.owner.phone}</a>
   232→                                ) : null}
   233→                              </>
   234→                            ) : (
   235→                              <span>{custB?.vessel.owner.name}</span>
   236→                            )}
   237→                          </div>
   238→                          <div className="flex flex-wrap items-center gap-2 mt-1">
   239→                            {b.stayingOnMooring ? (
   240→                              <span className="inline-flex items-center rounded-full bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-700">
   241→                                Staying on mooring
   242→                              </span>
   243→                            ) : null}
   244→                            <span className="text-xs text-zinc-400">
   245→                              Completed {b.completedAt ? new Date(b.completedAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) : "—"}
   246→                            </span>
   247→                          </div>
   248→                        </div>
   249→                      </div>
   250→                    );
   251→                  })}
   252→                </div>
   253→              )}
   254→            </CardContent>
   255→          </Card>
   256→        </div>
   257→      </div>
   258→    );
   259→  };
   260→
   261→  return (
   262→    <div className="space-y-8">
   263→      {/* Page header */}
   264→      <div className="flex flex-wrap items-center justify-between gap-3">
   265→        <div>
   266→          <h1 className="text-2xl font-semibold tracking-tight">Live Queues</h1>
   267→          <p className="mt-1 text-sm text-zinc-600">Both queues · auto-refreshes every 3 minutes.</p>
   268→        </div>
   269→        <Button variant="secondary" onClick={load} disabled={loading}>
   270→          Refresh
   271→        </Button>
   272→      </div>
   273→
   274→      {/* Launch Queue Section */}
   275→      {renderQueueSection("LAUNCH", launchData)}
   276→
   277→      {/* Retrieval Queue Section */}
   278→      {renderQueueSection("RETRIEVAL", retrievalData)}
   279→    </div>
   280→  );
   281→}
