     3→let audioCtx: AudioContext | null = null;
     4→
     5→function getAudioContext(): AudioContext | null {
     6→  if (typeof window === "undefined") return null;
     7→  if (!audioCtx) {
     8→    try {
     9→      audioCtx = new AudioContext();
    10→    } catch {
    11→      return null;
    12→    }
    13→  }
    14→  return audioCtx;
    15→}
    16→
    17→function playTone(
    18→  frequency: number,
    19→  duration: number,
    20→  gainPeak: number,
    21→  type: OscillatorType,
    22→  startOffset = 0,
    23→  ctx?: AudioContext,
    24→) {
    25→  const context = ctx ?? getAudioContext();
    26→  if (!context) return;
    27→
    28→  const oscillator = context.createOscillator();
    29→  const gainNode = context.createGain();
    30→
    31→  oscillator.connect(gainNode);
    32→  gainNode.connect(context.destination);
    33→
    34→  oscillator.type = type;
    35→  oscillator.frequency.setValueAtTime(frequency, context.currentTime + startOffset);
    36→
    37→  const t0 = context.currentTime + startOffset;
    38→  gainNode.gain.setValueAtTime(0, t0);
    39→  gainNode.gain.linearRampToValueAtTime(gainPeak, t0 + 0.01);
    40→  gainNode.gain.exponentialRampToValueAtTime(0.001, t0 + duration);
    41→
    42→  oscillator.start(t0);
    43→  oscillator.stop(t0 + duration);
    44→}
    45→
    46→/**
    47→ * Launch alert — three ascending bright tones (boat going UP into the water).
    48→ * Plays when a new launch booking enters the queue.
    49→ */
    50→export function playLaunchAlert() {
    51→  const ctx = getAudioContext();
    52→  if (!ctx) return;
    53→  void ctx.resume().then(() => {
    54→    playTone(660, 0.35, 0.22, "sine", 0, ctx);
    55→    playTone(880, 0.35, 0.22, "sine", 0.16, ctx);
    56→    playTone(1320, 0.55, 0.20, "sine", 0.32, ctx);
    57→  });
    58→}
    59→
    60→/**
    61→ * Retrieval alert — three descending warm tones (boat coming DOWN out of the water).
    62→ * Plays when a new retrieval booking enters the queue.
    63→ */
    64→export function playRetrievalAlert() {
    65→  const ctx = getAudioContext();
    66→  if (!ctx) return;
    67→  void ctx.resume().then(() => {
    68→    playTone(880, 0.35, 0.22, "triangle", 0, ctx);
    69→    playTone(660, 0.35, 0.22, "triangle", 0.16, ctx);
    70→    playTone(440, 0.55, 0.20, "triangle", 0.32, ctx);
    71→  });
    72→}
