     9→export async function GET(req: NextRequest) {
    10→  const { searchParams } = new URL(req.url);
    11→  const lat = searchParams.get("lat");
    12→  const lon = searchParams.get("lon");
    13→  const timezone = searchParams.get("timezone") || "America/Vancouver";
    14→
    15→  if (!lat || !lon) {
    16→    return NextResponse.json({ error: "lat and lon required" }, { status: 400 });
    17→  }
    18→
    19→  try {
    20→    const fetchPromises: Promise<Response>[] = [
    21→      fetch(
    22→        `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current=temperature_2m,wind_speed_10m,wind_direction_10m,weather_code,is_day&daily=sunrise,sunset&wind_speed_unit=kmh&timezone=${encodeURIComponent(timezone)}`,
    23→        { next: { revalidate: 300 } }
    24→      ),
    25→      fetch(
    26→        `https://marine-api.open-meteo.com/v1/marine?latitude=${lat}&longitude=${lon}&current=wave_height,wave_direction,wave_period&timezone=${encodeURIComponent(timezone)}`,
    27→        { next: { revalidate: 300 } }
    28→      ),
    29→    ];
    30→
    31→    // WorldTides API for accurate high/low tide predictions
    32→    // Sign up free at https://www.worldtides.info (100 lookups/day)
    33→    // Add WORLDTIDES_API_KEY to your .env.local or Vercel env vars to enable tides
    34→    const tidesKey = process.env.WORLDTIDES_API_KEY;
    35→    if (tidesKey) {
    36→      const today = new Date().toISOString().slice(0, 10);
    37→      fetchPromises.push(
    38→        fetch(
    39→          `https://www.worldtides.info/api/v3?extremes&lat=${lat}&lon=${lon}&key=${tidesKey}&days=2&date=${today}`,
    40→          { next: { revalidate: 3600 } }
    41→        )
    42→      );
    43→    }
    44→
    45→    const results = await Promise.all(fetchPromises);
    46→    const weather = await results[0].json();
    47→    const marine = await results[1].json();
    48→
    49→    let tides: TideEvent[] | null = null;
    50→    if (tidesKey && results[2]) {
    51→      const tidesData = await results[2].json();
    52→      const now = new Date();
    53→      const extremes = (tidesData.extremes ?? []) as Array<{ dt: number; height: number; type: string }>;
    54→      tides = extremes
    55→        .filter((e) => new Date(e.dt * 1000) > now)
    56→        .slice(0, 4)
    57→        .map((e) => ({
    58→          time: new Date(e.dt * 1000).toISOString(),
    59→          height: Math.round(e.height * 10) / 10,
    60→          type: e.type === "High" ? "high" : "low",
    61→        }));
    62→    }
    63→
    64→    return NextResponse.json({
    65→      temperature: weather.current?.temperature_2m ?? null,
    66→      windSpeed: weather.current?.wind_speed_10m ?? null,
    67→      windDirection: weather.current?.wind_direction_10m ?? null,
    68→      weatherCode: weather.current?.weather_code ?? null,
    69→      isDay: weather.current?.is_day ?? null,
    70→      sunrise: weather.daily?.sunrise?.[0] ?? null,
    71→      sunset: weather.daily?.sunset?.[0] ?? null,
    72→      waveHeight: marine.current?.wave_height ?? null,
    73→      wavePeriod: marine.current?.wave_period ?? null,
    74→      tides,
    75→    });
    76→  } catch {
    77→    return NextResponse.json({ error: "Failed to fetch conditions" }, { status: 500 });
    78→  }
    79→}
